  ('e3e36ca3-90e8-494c-afad-59fe923de2d7', 'KIMCHI-5400', 'Udon Nabeyaki Kitsune Soup in Bowl 210g - Itsuki', 'Udon Nabeyaki Kitsune Soup in Bowl 210g - Itsuki. This aluminum bowl can be placed on a gas stove, no pot needed.', 'Udon Nabeyaki Kitsune Soup in Bowl 210g - Itsuki', 'Udon Nabeyaki Kitsune Soup in Bowl 210g - Itsuki. This aluminum bowl can be placed on a gas stove, no pot needed.'),
  ('5ea9c104-9843-4674-b8e5-9af5c88cc51a', 'KIMCHI-4338', 'Udon Nabeyaki Sukiyaki Soup in Bowl 235g - Itsuki', 'Udon Nabeyaki Sukiyaki Soup in Bowl 235g - Itsuki', 'Udon Nabeyaki Sukiyaki Soup in Bowl 235g - Itsuki', 'Udon Nabeyaki Sukiyaki Soup in Bowl 235g - Itsuki'),
  ('10cd0a62-442f-420b-ab0a-2fe52b51c159', 'KIMCHI-2487', 'Yeul Ramen, Beef with Spicy Mushrooms 120g - Ottogi', 'Yeul Ramen, Beef with Spicy Mushrooms 120g - Ottogi', 'Yeul Ramen, Beef with Spicy Mushrooms 120g - Ottogi', 'Yeul Ramen, Beef with Spicy Mushrooms 120g - Ottogi'),
  ('7f65cdd7-c7bd-4076-9b43-a5ce433c759d', 'KIMCHI-5502', 'Yude Udon Fresh Noodles 3x209g - Itsuki', 'Yude Udon Fresh Noodles 3x209g - Itsuki', 'Yude Udon Fresh Noodles 3x209g - Itsuki', 'Yude Udon Fresh Noodles 3x209g - Itsuki')
), matched AS (
  SELECT
    p.salon_id,
    p.id AS template_id,
    s.slug,
    s.product_name,
    s.short_description,
    s.meta_title,
    s.meta_description
  FROM source s
  JOIN channels ch ON ch.slug = 'asiandeligo' AND ch.is_active = true
  JOIN products p ON p.id = s.template_id::uuid AND p.salon_id = ch.salon_id
  WHERE p.deleted_at IS NULL
), backup_insert AS (
  INSERT INTO asiandeligo_product_translations_backup_20260708
  SELECT pt.*
  FROM product_translations pt
  JOIN matched m ON m.template_id = pt.template_id AND m.salon_id = pt.salon_id
  WHERE pt.lang_id = 'en'
    AND NOT EXISTS (SELECT 1 FROM asiandeligo_product_translations_backup_20260708 b WHERE b.id = pt.id)
  RETURNING id
), upserted AS (
  INSERT INTO product_translations (
    id, salon_id, template_id, lang_id, product_name, short_description,
    meta_title, meta_description, created_at, updated_at
  )
  SELECT
    gen_random_uuid(),
    salon_id,
    template_id,
    'en',
    product_name,
    short_description,
    meta_title,
    meta_description,
    NOW(),
    NOW()
  FROM matched
  ON CONFLICT (template_id, lang_id) DO UPDATE SET
    product_name = EXCLUDED.product_name,
    short_description = EXCLUDED.short_description,
    meta_title = EXCLUDED.meta_title,
    meta_description = EXCLUDED.meta_description,
    updated_at = NOW()
  WHERE product_translations.salon_id = EXCLUDED.salon_id
  RETURNING template_id
)
SELECT
  (SELECT COUNT(*) FROM source) AS source_rows,
  (SELECT COUNT(*) FROM matched) AS matched_rows,
  (SELECT COUNT(*) FROM backup_insert) AS backed_up_rows,
  (SELECT COUNT(*) FROM upserted) AS upserted_rows;

-- Verify the printed counts after running. The backup table can be used to restore previous EN rows if needed.
COMMIT;
